UPDATE custom_field_def
SET description = 'Identifiant normalisé et stable du bien immobilier, utilisé comme nom de dossier. RÈGLE DE NORMALISATION : [ville]-[type-de-voie]-[nom], en minuscules, sans numéro de rue, sans code postal, sans accent. Le type de voie (rue, avenue, boulevard, place, impasse, chaussee, cours, promenade, allee…) est TOUJOURS inclus - il fait partie du nom et lève les ambiguïtés (rue de la Republique ≠ place de la Republique). Le numéro et le code postal sont intentionnellement exclus car ils sont souvent absents ou dans un ordre variable selon les documents. Exemples : paris-rue-oberkampf, nice-promenade-des-anglais, lyon-place-de-la-republique, bordeaux-cours-victor-hugo, bruxelles-avenue-de-la-biqueterie, bruxelles-chaussee-de-wavre, bruxelles-place-condorcet, bruxelles-impasse-boileau. Si plusieurs biens sont dans la même ville sur la même voie, ajouter un discriminant minimal (ex: paris-rue-oberkampf-2eme). IMPORTANT : tous les documents d''un même bien doivent produire TOUJOURS le même identifiant, quelle que soit la façon dont l''adresse est écrite sur le document.'
WHERE slug = 'adresse_bien';
